class LRUCache {
public:
    LRUCache(int capacity) {
        cap = capacity;
        cache = new list<pair<int, int>>();
    }

    int get(int key) {
        for (auto it = cache->begin(); it != cache->end(); ++it) {
            if (it->first == key) {
                cache->erase(it);
                cache->push_back(make_pair(key, it->second));
                return it->second;
            }
        }
        return -1;
    }

    void put(int key, int value) {
        for (auto it = cache->begin(); it != cache->end(); ++it) {
            if (it->first == key) {
                cache->erase(it);
                cache->push_back(make_pair(key, value));
                return;
            }
        }
        if (cache->size() == cap) {
            cache->pop_front();
        }
        cache->push_back(make_pair(key, value));
    }
private:
    int cap;
    list<pair<int, int>>* cache;
};
```

